CREATE PROCEDURE backfill_mes_semana()
BEGIN
    DECLARE batch_size INT DEFAULT 1000;
    DECLARE affected INT DEFAULT 1;

    -- albaran
    SET affected = 1;
    WHILE affected > 0 DO
        UPDATE albaran SET mes = MONTH(fecha), semana = WEEK(fecha, 3) WHERE mes = 0 LIMIT batch_size;
        SET affected = ROW_COUNT();
    END WHILE;

    -- prefactura
    SET affected = 1;
    WHILE affected > 0 DO
        UPDATE prefactura SET mes = MONTH(fecha), semana = WEEK(fecha, 3) WHERE mes = 0 LIMIT batch_size;
        SET affected = ROW_COUNT();
    END WHILE;

    -- factura
    SET affected = 1;
    WHILE affected > 0 DO
        UPDATE factura SET mes = MONTH(fecha), semana = WEEK(fecha, 3) WHERE mes = 0 LIMIT batch_size;
        SET affected = ROW_COUNT();
    END WHILE;
END
